import{_ as i,o,c as t,a3 as a}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Module Development — Production Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Module Development — Production Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/module-development"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Module Development — Production Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/module-development"}]]},"headers":[],"relativePath":"deployment/module-development.md","filePath":"deployment/module-development.md","lastUpdated":1784746021000}'),n={name:"deployment/module-development.md"};function l(s,e,r,d,c,p){return o(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="module-development-—-production-guide" tabindex="-1">Module Development — Production Guide <a class="header-anchor" href="#module-development-—-production-guide" aria-label="Permalink to &quot;Module Development — Production Guide&quot;">​</a></h1><h2 id="licensing" tabindex="-1">Licensing <a class="header-anchor" href="#licensing" aria-label="Permalink to &quot;Licensing&quot;">​</a></h2><ul><li>Active license = <code>workspace_module_subscriptions</code> in <code>trial</code> / <code>active</code> (and not ended).</li><li><code>EnsureModule</code> (<code>module:{slug}</code>) returns 403/402-style denial when the workspace lacks the module.</li><li>Default-included modules (<code>is_default_included</code>) install on workspace provision; platform admins may deactivate.</li><li>Entitlements cache: <code>workspace:{id}:entitlements</code> (1 hour); invalidated on install/cancel/deactivate.</li></ul><h2 id="workspace-bootstrap-explicit-provisioning" tabindex="-1">Workspace bootstrap (explicit provisioning) <a class="header-anchor" href="#workspace-bootstrap-explicit-provisioning" aria-label="Permalink to &quot;Workspace bootstrap (explicit provisioning)&quot;">​</a></h2><p>On workspace create (<code>TenantProvisioningService</code>):</p><ol><li>Billing profile</li><li>Default modules installed</li><li>Authorization defaults via <code>TenantAuthorizationProvisioningService</code> (roles + permission maps)</li><li>Module-specific seed data (e.g. default lead stages)</li><li>Owner user created (<code>TenantAuthBootstrapService::createOwner</code>) — <strong>no</strong> RBAC side effects on login afterward</li></ol><p>Authentication, dashboard, and role/user listing never repair permissions.</p><h2 id="shipping-a-new-default-included-module" tabindex="-1">Shipping a new default-included module <a class="header-anchor" href="#shipping-a-new-default-included-module" aria-label="Permalink to &quot;Shipping a new default-included module&quot;">​</a></h2><p>Use <strong>data migrations</strong>, not production seeders:</p><ol><li>Schema migration(s)</li><li>Catalog data migration → <code>App\\Support\\Catalog\\DefaultModuleRegistrar</code></li><li>Permission data migration → <code>App\\Support\\Permissions\\TenantPermissionSynchronizer::grantMissingDefaultRolePermissions([...])</code></li><li>Deploy with:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> optimize</span></span></code></pre></div><p>Keep <code>CatalogSeeder</code> updated for <strong>local/CI fresh databases only</strong>. Do <strong>not</strong> run <code>db:seed</code> / <code>CatalogSeeder</code> in production to register modules.</p><p>Never <code>syncPermissions()</code> against existing customized roles during deploy. Grants must be additive and idempotent.</p><h3 id="what-defaultmoduleregistrar-guarantees" tabindex="-1">What DefaultModuleRegistrar guarantees <a class="header-anchor" href="#what-defaultmoduleregistrar-guarantees" aria-label="Permalink to &quot;What DefaultModuleRegistrar guarantees&quot;">​</a></h3><ul><li><code>firstOrCreate</code> by module slug — never overwrites commercial flags, prices, or renamed fields</li><li>Installs subscriptions only when a workspace has <strong>never</strong> had a row for that module (checks soft-deleted)</li><li>Does not reactivate cancelled / suspended / soft-deleted subscriptions</li></ul><h3 id="what-tenantpermissionsynchronizer-guarantees" tabindex="-1">What TenantPermissionSynchronizer guarantees <a class="header-anchor" href="#what-tenantpermissionsynchronizer-guarantees" aria-label="Permalink to &quot;What TenantPermissionSynchronizer guarantees&quot;">​</a></h3><ul><li>Creates missing permission vocabulary from <code>config/tenant-permissions.php</code></li><li>Grants <strong>only the listed</strong> new permission names to default roles that should have them</li><li>Leaves customized role edits intact</li></ul><h2 id="monitoring" tabindex="-1">Monitoring <a class="header-anchor" href="#monitoring" aria-label="Permalink to &quot;Monitoring&quot;">​</a></h2><ul><li>Platform audit log (<code>activity</code> log name <code>platform</code>) for install, assign, destructive actions</li><li>Spatie activity on domain models for attribute changes</li><li>Nightwatch / Telescope for exceptions on module routes</li><li>Stripe / gateway logs remain under Billing — modules must not bypass them</li></ul><h2 id="deploy-checklist" tabindex="-1">Deploy checklist <a class="header-anchor" href="#deploy-checklist" aria-label="Permalink to &quot;Deploy checklist&quot;">​</a></h2><ol><li>Run migrations (<code>php artisan migrate --force</code>) — include <strong>data migrations</strong> for catalog rows and additive permission grants</li><li>Do <strong>not</strong> rely on <code>CatalogSeeder</code> / <code>db:seed</code> in production for new default modules</li><li>Confirm <code>tenant-permissions</code> + <code>tenant-default-role-permissions</code> config are deployed with the release (migrations read them)</li><li>Entitlement cache is cleared per workspace by the module registrar when a subscription is newly installed</li><li>If the module contributes dashboard widgets or notifications, confirm scheduler (<code>crm:send-due-notifications</code>) and SPA polling/widget ids</li><li>Smoke: login → module nav visible → list API 200 with <code>module:</code> + <code>can:</code></li></ol><h2 id="rollback" tabindex="-1">Rollback <a class="header-anchor" href="#rollback" aria-label="Permalink to &quot;Rollback&quot;">​</a></h2><ul><li>Soft-delete / deactivate module subscription to revoke licensing without dropping data</li><li>Keep domain tables; do not drop migrations in production without a data plan</li><li>Permission grant migrations are intentionally irreversible (do not revoke production role grants in <code>down()</code>)</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/deployment/communication-templates">Communication Templates deployment</a></li><li><a href="/deployment/platform-production-runbook">Platform production runbook</a></li><li><a href="/developer-guide/tenant-provisioning">Tenant provisioning</a></li></ul>`,25)])])}const h=i(n,[["render",l]]);export{m as __pageData,h as default};
